record.field:
{
    "type": "object",
    "properties": {
        "class_name": {"type": "string", "description": "Name of the class template"},
        "template_id": {"type": "integer", "description": "ID of the class template"},
        "start_datetime": {"type": "string", "format": "date-time", "description": "Start date/time (ISO 8601)"}
    },
    "required": ["class_name"]
}

{
    "type": "object",
    "properties": {
        "class_name": {"type": "string", "description": "Name of the class"},
        "session_id": {"type": "integer", "description": "ID of the session to cancel"}
    }
}

{
    "type": "object",
    "properties": {
        "name": {"type": "string", "description": "Name of the class template"},
        "program_name": {"type": "string", "description": "Name of the program this class belongs to"},
        "max_capacity": {"type": "integer", "description": "Max students per session", "default": 20},
        "level": {"type": "string", "description": "Class difficulty level"},
        "duration_minutes": {"type": "integer", "description": "Duration in minutes", "default": 60},
        "active": {"type": "boolean", "description": "Whether the template is active", "default": true}
    },
    "required": ["name"]
}

{
    "type": "object",
    "properties": {
        "overdue": {"type": "boolean", "description": "Only show overdue tasks"},
        "project_name": {"type": "string", "description": "Filter by project name"},
        "member_name": {"type": "string", "description": "Filter tasks related to a specific member"},
        "include_done": {"type": "boolean", "description": "Include completed tasks"}
    }
}

{
    "type": "object",
    "required": ["name"],
    "properties": {
        "name": {"type": "string", "description": "Task title"},
        "description": {"type": "string", "description": "Task description or notes"},
        "date_deadline": {"type": "string", "format": "date", "description": "Deadline date (YYYY-MM-DD)"},
        "priority": {"type": "string", "enum": ["0", "1"], "description": "Priority: 0=Normal, 1=High"},
        "project_name": {"type": "string", "description": "Project to add task to (default: Instructor Alerts)"}
    }
}

{
    "type": "object",
    "properties": {
        "task_name": {"type": "string", "description": "Name or partial name of the task to complete"},
        "task_id": {"type": "integer", "description": "ID of the task"}
    }
}

{
    "type": "object",
    "properties": {
        "task_name": {"type": "string", "description": "Name of the task to update"},
        "task_id": {"type": "integer", "description": "ID of the task"},
        "date_deadline": {"type": "string", "format": "date", "description": "New deadline (YYYY-MM-DD)"},
        "note": {"type": "string", "description": "Note to add to the task"}
    }
}

{
    "type": "object",
    "required": ["name", "start"],
    "properties": {
        "name": {"type": "string", "description": "Event title"},
        "start": {"type": "string", "description": "Start date/time (YYYY-MM-DD HH:MM)"},
        "stop": {"type": "string", "description": "End date/time (YYYY-MM-DD HH:MM)"},
        "duration_minutes": {"type": "integer", "description": "Duration in minutes (default: 60)"},
        "description": {"type": "string", "description": "Event description"},
        "location": {"type": "string", "description": "Event location"}
    }
}

{
    "type": "object",
    "properties": {
        "event_name": {"type": "string", "description": "Name or partial name of the event"},
        "event_id": {"type": "integer", "description": "ID of the event"},
        "start": {"type": "string", "description": "Start date to disambiguate events with same name"}
    }
}
